import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

import java.util.Scanner;

public class XSSFixedExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Properly encode user input to prevent XSS
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encodeForHTML(userInput);

        System.out.println("<p>Welcome, " + encodedInput + "!</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
